var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"쓰러트렸어......?","JPN":"倒した……？","ENG":"He beat it?","TWN":"打倒了？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체를?","JPN":"第4種侵食体を？","ENG":"He beat a Category 4 C.O.?","TWN":"他把4類侵蝕體打倒了？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"여, 역시 델타세븐 최강의 전투요원답군요.","JPN":"さ、さすがデルタセブンきっての最強戦闘員。","ENG":"Y-you're Delta Seven's strongest combatant for a reason.","TWN":"不、不愧是第七三角洲的最強戰鬥要員。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대단하십니다, 소령님......","JPN":"すごすぎます、少佐……","ENG":"You're amazing, Major.","TWN":"太了不起了，少校大人……"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":" 쿨럭! 쿨럭!","JPN":"ゲホッ！　ゲホッ！","ENG":" *Cough!* *Cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아직 무리하지 마! 상처가 심하다고!","JPN":"まだ無理しちゃダメよ！　ひどいケガなんだから！","ENG":"Stop moving! You're badly wounded!","TWN":"你還不能太勉強！你的傷太重了！"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......놀라서 말이 안 나오는군.","JPN":"……こりゃ、驚きすぎて言葉も出てこないな。","ENG":"I'm so shocked that I'm at a loss for words.","TWN":"……我驚訝到都說不出話來了。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"단독으로 제 4종 침식체를 격퇴하다니......","JPN":"単独で第4種侵食体を撃退するなんて……","ENG":"You singlehandedly beat a Category 4 C.O.","TWN":"竟然獨自擊退了4類侵蝕體……"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"상부는 대체 왜 이런 부대의 정식 배치를 반대하는 거지?","JPN":"上層部はなぜこんな部隊の正規認定に反対するんだ？","ENG":"Why does the brass refuse to officially acknowledge such a strong unit?","TWN":"上面究竟為什麼反對將這樣的部隊轉為正式部隊？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"일어설 수 있겠나?","JPN":"自力で立てそうか？","ENG":"Can you stand up?","TWN":"能站起來嗎？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럭저럭......","JPN":"なんとかな……","ENG":"I think so.","TWN":"勉強還行吧……"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"당신이 목숨을 걸어준 덕분에 등대의 핵심 부품을 지킬 수 있다고 들었어.","JPN":"君が体を張ってくれたおかげで、灯台のコアを守れたと聞いた。","ENG":"I heard you risked your life to protect the Lighthouse's core component.","TWN":"我聽說了多虧你拚上性命，我們才保住了燈塔的核心部件。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님 대신 감사를 표하지.","JPN":"司令官の代わりに礼をしたい。","ENG":"I'd like to thank you on behalf of the Commander.","TWN":"我代替司令官向你表示感謝。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"별거 아니야.","JPN":"大したことない。","ENG":"It's nothing.","TWN":"沒什麼。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그리고 감사라면 이쪽에서 해야지, 생명의 은인인데 말이야.","JPN":"それに感謝ならこっちがすべきだろ、命の恩人だからな。","ENG":"Besides, I should thank you. You saved my life.","TWN":"而且應該是我感謝你才對，你可是我的救命恩人。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그나저나 같이 간 길잡이는 어떻게 됐나? 보이질 않는데.","JPN":"それより同行した道案内役はどこだ？　見当たらないんだが。","ENG":"By the way, what happened to your guide? I don't see him anywhere.","TWN":"不過和你一起去的帶路人怎麼樣了？我怎麼沒看到他。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......나도 모르겠군. 갑자기 사라졌어.","JPN":"……俺にもわからない。急に消えちまったんだ。","ENG":"Beats me. He disappeared all of a sudden.","TWN":"……我也不知道，他突然消失了。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};